import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut } from 'lucide-react';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [message, setMessage] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  // This part checks if you are ALREADY logged in when the page loads
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      setIsLoggedIn(true);
      setMessage('You are currently logged in.');
    }
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/api/auth/login', formData);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('userName', res.data.user.name); // Save name too
      setMessage(`Welcome back, ${res.data.user.name}!`);
      setIsLoggedIn(true);
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Login Failed');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userName');
    setIsLoggedIn(false);
    setMessage('Logged out successfully.');
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <div className="p-8 bg-white shadow-2xl rounded-2xl w-96 border-t-4 border-blue-600 text-center">
        
        <div className="flex justify-center mb-6 text-blue-600">
          <LogIn size={48} />
        </div>
        <h2 className="text-2xl font-bold text-gray-800 mb-6">QuadSolutions Portal</h2>
        
        {!isLoggedIn ? (
          <form onSubmit={handleSubmit} className="space-y-4 text-left">
            <div className="relative">
              <Mail className="absolute left-3 top-3 text-gray-400" size={20} />
              <input
                type="email"
                placeholder="Email Address"
                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                required
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
              <input
                type="password"
                placeholder="Password"
                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                required
              />
            </div>
            <button className="w-full bg-blue-600 text-white py-2 rounded-lg font-semibold hover:bg-blue-700">
              Sign In
            </button>
            {message && <p className="text-red-500 text-sm mt-2">{message}</p>}
          </form>
        ) : (
          <div>
            <p className="text-green-600 font-bold mb-6 text-lg">
              {message || `Welcome, ${localStorage.getItem('userName')}!`}
            </p>
            <button 
              onClick={handleLogout}
              className="flex items-center justify-center w-full bg-red-500 text-white py-2 rounded-lg font-semibold hover:bg-red-600 transition duration-300"
            >
              <LogOut size={18} className="mr-2" />
              Logout
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Login;
